#include <stdio.h>
#include <string.h>

#define MAX_LIMIT 50

int main(void) {
    // Allocate space for 49 characters plus 1 null terminator
    char username[MAX_LIMIT];

    printf("Enter your full name (max %d chars): ", MAX_LIMIT - 1);

    // fgets is safe; it reads until a newline or MAX_LIMIT-1 limit is met
    if (fgets(username, sizeof(username), stdin) != NULL) {

        // fgets retains the newline character '\n' if there is space. Let's strip it.
        size_t len = strlen(username);
        if (len > 0 && username[len - 1] == '\n') {
            username[len - 1] = '\0';
        }

        printf("Successfully read name: \"%s\"\n", username);
        printf("Length of string is: %zu bytes\n", strlen(username));
    }
    return 0;
}

