#include <stdio.h>
#include <string.h>
#include <ctype.h>

// Manual implementation of a case-insensitive character finder
const char* find_char_ignore_case(const char *str, char target) {
    if (str == NULL) return NULL;

    char target_lower = tolower((unsigned char)target);

    while (*str != '\0') {
        if (tolower((unsigned char)*str) == target_lower) {
            return str; // Return pointer to matching char
        }
        str++; // Move pointer forward manually
    }
    return NULL;
}

int main(void) {
    char phrase[] = "Mastering C Strings!";
    char search_char = 'c';

    // Using modern strncpy securely
    char destination[10];
    strncpy(destination, phrase, sizeof(destination) - 1);
    destination[sizeof(destination) - 1] = '\0'; // Crucial manual safe termination

    printf("Original: %s\n", phrase);
    printf("Truncated copy: %s\n", destination);

    // Manual lookup execution
    const char *match = find_char_ignore_case(phrase, search_char);
    if (match != NULL) {
        printf("Found character '%c' at position (offset): %ld\n", search_char, match - phrase);
    } else {
        printf("Character '%c' not found.\n", search_char);
    }

    return 0;
}

