#include <stddef.h>
#include <string.h>

int safe_strcat(char *dest, const char *src, size_t dest_capacity) {
    if (dest == NULL || src == NULL || dest_capacity == 0) return 0;

    size_t dest_len = strlen(dest);
    if (dest_len >= dest_capacity) return 0; // Pre-existing overflow check

    size_t available_space = dest_capacity - dest_len - 1;

    size_t i;
    for (i = 0; i < available_space && src[i] != '\0'; i++) {
        dest[dest_len + i] = src[i];
    }

    dest[dest_len + i] = '\0'; // Always guarantee safe null-termination

    return (src[i] == '\0') ? 1 : 0; // Return 1 if complete src was appended, 0 if truncated
}

The strcmp function returns 0 when two strings are identical. It returns values other than 0 (either negative or positive) when strings do not match. Comparing strcmp's result to 1 is incorrect because different system implementations can return any positive or negative values when comparisons fail. To test for string matching, check for equality with 0 instead:

Correct code:
if (strcmp(input, "exit") == 0) {
