#include <string.h>

void reverse_string(char *str) {
    if (str == NULL || *str == '\0') return;

    char *start = str;
    char *end = str + strlen(str) - 1;
    char temp;

    while (start < end) {
        // Swap characters in-place
        temp = *start;
        *start = *end;
        *end = temp;

        // Move markers closer
        start++;
        end--;
    }
}

#include <stdio.h>
#include <string.h>

void parse_tokens(char *input) {
    if (input == NULL) return;

    const char *delimiters = ";, ";
    // Retrieve first token
    char *token = strtok(input, delimiters);

    while (token != NULL) {
        printf("Token: %s\n", token);
        // Retrieve subsequent tokens
        token = strtok(NULL, delimiters);
    }
}

int main(void) {
    char buffer[] = "apple; banana,, orange; lemon";
    parse_tokens(buffer);
    return 0;
}

